  ('pukao-e3452428-moex-00557', 'pukao-e3452428', 'pukao-e3452428-moex-111-d1a761c9', 'sub-pukao-e3452428-03', NULL, 'single_choice', '依行政訴訟法規定，下列何者非確認訴訟之種類？', '["確認已消滅之行政處分違法之訴訟", "確認行政事實行為違法之訴訟", "確認行政處分無效之訴訟", "確認公法上法律關係成立或不成立之訴訟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "402", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00558', 'pukao-e3452428', 'pukao-e3452428-moex-111-d1a761c9', 'sub-pukao-e3452428-03', NULL, 'single_choice', '已核准退休公務員請求服務機關發給退休金，應選擇下列何者訴訟類型？', '["撤銷訴訟", "課予義務訴訟", "確認訴訟", "一般給付訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "402", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00559', 'pukao-e3452428', 'pukao-e3452428-moex-111-d1a761c9', 'sub-pukao-e3452428-03', NULL, 'single_choice', '甲違規停放汽車，經臺北市政府警察局北投分局警員乙指揮受臺北市政府警察局委託之 A 民間拖吊公司 實施違規拖吊，因A公司員工操作不當，致甲之車受損。甲依法應採取如何途徑尋求權利救濟？', '["依行政執行法規定向臺北市政府警察局北投分局聲明異議", "依國家賠償法規定向A公司請求賠償", "依訴願法規定向臺北市政府提起訴願", "依國家賠償法規定以書面向臺北市政府警察局北投分局請求進行賠償協議"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "402", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00560', 'pukao-e3452428', 'pukao-e3452428-moex-111-d1a761c9', 'sub-pukao-e3452428-03', NULL, 'single_choice', '某些公務員因執行職務侵害人民自由或權利，必須就其職務上之犯罪經判決有罪確定者，始能適用國家賠 償法，下列何者不屬之？', '["檢察官", "民事庭法官", "司法事務官", "行政法院法官"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "402", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00561', 'pukao-e3452428', 'pukao-e3452428-moex-111-d1a761c9', 'sub-pukao-e3452428-03', NULL, 'single_choice', '某道路橋樑之耐震設計不當，致大貨車通過時，橋樑崩塌斷裂壓傷甲，經送醫不治死亡。有關甲之國家賠 償，下列敘述何者錯誤？', '["賠償範圍包括醫藥費、喪葬費", "甲之配偶、子女得請求非財產上損害賠償", "賠償義務機關賠償後，不得對橋樑設計廠商求償", "甲之父親得請求相當於扶養費之損害賠償"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "402", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00562', 'pukao-e3452428', 'pukao-e3452428-moex-111-d1a761c9', 'sub-pukao-e3452428-03', NULL, 'single_choice', '關於損失補償之敘述，下列何者錯誤？', '["人民因機關即時強制致財產損失，得請求補償", "損失補償原則上以金錢為之，並以實際損失為限", "不服損失補償之決定，得提起給付訴訟", "授予利益之違法行政處分遭撤銷，相對人主張信賴保護而請求損失補償遭拒，得提起訴願"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "402", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00563', 'pukao-e3452428', 'pukao-e3452428-moex-110-77777d6f', 'sub-pukao-e3452428-01', NULL, 'essay', '社區是居民生活成長的地方，社區的經營會影響居民的生活品質，故社
區營造是很重要的，政府也花費許多資源，制訂與執行許多相關政策。
但在執行時，可能會面臨一些問題與困境，請問：
